class Solution {
    public List<String> removeInvalidParentheses(String s) {
        Set<String> result = new HashSet<>();
        removeInvalidParenthesesHelper(s, 0, 0, 0, result);
        return new ArrayList<>(result);
    }
    private void removeInvalidParenthesesHelper(String s, int left, int right, int index, Set<String> result) {
        if (index == s.length()) {
            if (left == right) {
                result.add(s);
            }
            return;
        }
        char c = s.charAt(index);
        if (c == '(') {
            removeInvalidParenthesesHelper(s.substring(0, index) + s.substring(index + 1), left + 1, right, index + 1, result);
        } else if (c == ')') {
            removeInvalidParenthesesHelper(s.substring(0, index) + s.substring(index + 1), left, right + 1, index + 1, result);
        } else {
            removeInvalidParenthesesHelper(s.substring(0, index) + s.substring(index + 1), left, right, index + 1, result);
        }
    }
}
